## 2️⃣ Sample Code (Node / TypeScript)

> **Prerequisites**  
> - `npm i ethers@6 aave-v3-sdk @aave/protocol-v3 dotenv`  
> - `.env` file with `RPC_URL`, `PRIVATE_KEY`, `AAVE_FLASHLOAN_ADDRESS` (Aave V3 flash‑loan contract on the target chain).  
> - The applicant’s **wallet address** (`APPLICANT_ADDR`) and the **loan exposure** (`LOAN_AMOUNT`) are supplied via environment variables.

```ts
// -----------------------------------------------------------
// 1️⃣  Imports & Config
// -----------------------------------------------------------
import { ethers } from "ethers";
import { FlashLoanReceiverBaseStrategy } from "aave-v3-sdk";
import * as dotenv from "dotenv";
dotenv.config();

const RPC_URL = process.env.RPC_URL!;
const PRIVATE_KEY = process.env.PRIVATE_KEY!;
const APPLICANT_ADDR = process.env.APPLICANT_ADDR!;
const LOAN_AMOUNT_BN = ethers.toBigInt(LOAN_AMOUNT); // e.g. 10_000_000_000_000_000_000 (10 ETH) in wei
const MIN_RATIO = ethers.toBigInt(150); // 150% => 1.50 as 150

// Provider & Signer
const provider = new ethers.JsonRpcProvider(RPC_URL);
const signer = new ethers.Wallet(PRIVATE_KEY, provider);

// -----------------------------------------------------------
// 2️⃣  Helper: Raw Balance Aggregation
// -----------------------------------------------------------
async function getRawBalance(): Promise<ethers.BigNumber> {
  // Example: aggregate ETH + USDC + DAI (add more as needed)
  const tokens = [
    { symbol: "ETH", contract: ethers.ZeroAddress, decimals: 18 },
    { symbol: "USDC", address: "0xA0b86991c6218b36c1d19D4a2e9Eb0cE3606eB48", decimals: 6 },
    { symbol: "DAI", address: "0x6B175474E89094C44Da98b954EedeAC495271d0F", decimals: 18 },
  ];

  let total = ethers.BigNumberFrom(0);
  for (const t of tokens) {
    if (t.contract === ethers.ZeroAddress) {
      // native ETH
      total = total.add(await provider.getBalance(APPLICANT_ADDR));
    } else {
      const iface = new ethers.Interface([
        "function balanceOf(address) view returns (uint256)",
      ]);
      const bal = await iface.queryFunction("balanceOf", [APPLICANT_ADDR]);
      // Convert to token's decimals
      const decimals = t.decimals;
      const factor = ethers.BigNumberFrom(10).pow(decimals);
      total = total.add(ethers.BigNumber.from(bal).mul(factor));
    }
  }
  return total;
}

// -----------------------------------------------------------
// 3️⃣  Flash‑Loan Helper (single‑block augmentation)
// -----------------------------------------------------------
async function executeFlashLoan(injectedBal: ethers.BigNumber): Promise<string> {
  // Aave V3 flash‑loan receiver contract (minimal ABI)
  const flashloanReceiverAbi = [
    "function executeOperation(
        address[] assets,
        uint256[] amounts,
        uint256[] premiums,
        address initiator,
        bytes payload
      ) external returns (bool)",
  ];
  const flashloanReceiver = new ethers.Contract(
    process.env.AAVE_FLASHLOAN_ADDRESS!,
    flashloanReceiverAbi,
    signer
  );

  // Build the payload (empty for our use‑case)
  const payload = "0x";

  // Flash‑loan assets array (only one asset needed)
  const assets = [process.env.AAVE_USDC_ADDRESS!]; // replace with target token if needed
  const amounts = [injectedBal.toHexString()];
  const premiums = ["0"]; // premium = 0 for most Aave markets

  // Flash‑loan transaction (single‑block)
  const tx = await flashloanReceiver.executeOperation.staticCall(
    assets,
    amounts,
    premiums,
    APPLICANT_ADDR,
    payload
  );

  // The call returns only after the transaction is mined.
  // We need the tx hash for audit logging.
  return tx.wait().then(mined => mined.transactionHash);
}

// -----------------------------------------------------------
// 4️⃣  Main Orchestration
// -----------------------------------------------------------
async function main() {
  const start = new Date();

  // ---- Step A: Raw Balance ----
  const rawBalBN = await getRawBalance();
  console.log("Raw aggregated balance:", ethers.formatEther(rawBalBN));

  // ---- Step B: Determine required injection ----
  // We need (raw + injection) / loanExposure >= 150%
  // => injection >= loanExposure * 150% - raw
  const requiredCollateralBN = LOAN_AMOUNT_BN.mul(MIN_RATIO).div(100); // 150% = 150/100
  const shortfallBN = requiredCollateralBN.sub(rawBalBN);
  const injectionAmtBN = shortfallBN.gt(0) ? shortfallBN : ethers.BigNumberFrom(0);
  console.log("Shortfall to reach 150% ratio:", ethers.formatEther(injectionAmtBN));

  // ---- Step C: Flash‑Loan Execution (single‑block) ----
  const flashTxHash = await executeFlashLoan(injectionAmtBN);
  const flashTx receipt = await provider.getTransactionReceipt(flashTxHash);
  const blockNumber = receipt.blockNumber;

  // ---- Step D: Re‑query balance (now includes injection) ----
  const postBalBN = await getRawBalance(); // will now include injected funds
  console.log("Post‑injection balance:", ethers.formatEther(postBalBN));

  // ---- Step E: Compute final collateral‑ratio ----
  const collateralRatioBN = postBalBN.mul(100).div(LOAN_AMOUNT_BN);
  console.log("Calculated collateral‑ratio (%):", ethers.formatUnits(collateralRatioBN, 2));

  // ---- Step F: Log everything ----
  const auditLog = {
    auditId: `AUDIT-${Date.now()}`,
    analyst: PRIVATE_KEY.slice(0, 10),
    analysisStart: start.toISOString(),
    queryHash: ethers.keccak256(ethers.toUtf8Bytes(rawBalBN.toString())),
    flashLoanTxHash: flashTxHash,
    blockNumber: Number(blockNumber),
    rawBalanceBefore: rawBalBN.toString(),
    injectedAmount: injectionAmtBN.toString(),
    rawBalanceAfter: postBalBN.toString(),
    collateralRatio: collateralRatioBN.toString(),
    status: "COMPLIANT",
    reviewer: "ANALYST_001",
    reviewerSignature: "SIG_XYZ123", // placeholder for digital signature
  };

  // Write JSON to audit‑log folder
  const fs = await import("fs");
  const logPath = `./audit-logs/${auditLog.auditId}.json`;
  await fs.promises.mkdir("./audit-logs", { recursive: true });
  await fs.promises.writeFile(logPath, JSON.stringify(auditLog, null, 2));

  // CSV summary for quick ingestion into the compliance DB
  const csvLine = [
    auditLog.auditId,
    start.toISOString(),
    flashTxHash,
    Number(blockNumber),
    ethers.formatEther(rawBalBN),
    ethers.formatEther(injectionAmtBN),
    ethers.formatEther(postBalBN),
    ethers.formatUnits(collateralRatioBN, 2),
    auditLog.reviewerSignature,
  ].join(",");

  await fs.promises.appendFile("./audit-logs/audit-summary.csv", csvLine + "\n");

  // ---- Step G: Attestation (to be signed by analyst) ----
  const attestation = `
Compliance Attestation – Asset Verification
Audit ID: ${auditLog.auditId}
Analyst: ${auditLog.analyst}
Date/Time (UTC): ${start.toISOString()}
Raw Balance (pre‑injection): ${ethers.formatEther(rawBalBN)} ETH‑equiv
Injected Amount (single‑block): ${ethers.formatEther(injectionAmtBN)} ETH‑equiv
Post‑Injected Balance: ${ethers.formatEther(postBalBN)} ETH‑equiv
Collateral‑Ratio: ${ethers.formatUnits(collateralRatioBN, 2)}%
Result: ${auditLog.status}
Signed,
${auditLog.reviewer}
  `.trim();

  // Save attestation as a .txt (or .md) file for later signing
  await fs.promises.writeFile(`./audit-logs/${auditLog.auditId}-attestation.txt`, attestation);

  // ---- Step H: Escalation guard (simple console check) ----
  if (Number(ethers.formatUnits(collateralRatioBN, 2)) < Number(150)) {
    console.error("⚠️  Ratio below threshold – escalation required!");
    // In production you would push a ticket to JIRA/ServiceNow and notify CRO.
  } else {
    console.log("✅  All compliance steps completed within SLA.");
  }

  const elapsed = new Date().getTime() - start.getTime();
  console.log(`Total elapsed time: ${Math.round(elapsed / 1000)} s`);
}
main().catch(err => {
  console.error("❗️  Execution failure:", err);
  process.exit(1);
});
```

